body:
I hope verilator can did the following example code. 
Main synthesizer have supported this feature. It's very convenient to insert some DFT code into design.

```Verilog

module  sub2 (
  input  clk, rst,
  input  d,
  output stat,
  output reg q
);

assign  stat = ~q;

always @(posedge clk)
if (rst)
    q<=0;
else
    q<=d;
  
endmodule

module  sub1 (
  input  d,
  output q
);

sub2 sub2(.d(d), .q(q));
  
endmodule

module  top (
  input  clk, rst,
  input  d,
  output q, stat
);

sub1 sub1(.d(d), .q(q));

assign  sub1.sub2.clk = clk;     //cross hierarchy assignment
assign  sub1.sub2.rst = rst;      //cross hierarchy assignment
assign  stat = sub1.sub2.stat;  //cross hierarchy assignment
  
endmodule

```
